body.script:
const callId = ;
const customerNumber = '';
const customerName = '';

let device;
let activeConnection;
let mediaRecorder;
let audioChunks = [];
let timerInterval;
let callStartTime;
let isMuted = false;

// Initialize on page load
document.addEventListener('DOMContentLoaded', function() {
    _log('Initializing Twilio phone interface...');
    initializeTwilio();
});

function _log(msg) {
    console.log('[Twilio] ' + msg);
}

function _error(msg) {
    console.error('[Twilio Error] ' + msg);
    showError(msg);
}

function showError(msg) {
    const errorBox = document.getElementById('error-box');
    errorBox.textContent = msg;
    errorBox.style.display = 'block';
}

async function initializeTwilio() {
    try {
        _log('Fetching Twilio token...');

        // Get Twilio token
        const response = await fetch(`/twilio/call/${callId}/token`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
        });

        const data = await response.json();
        _log('Token response: ' + JSON.stringify(data));

        if (data.error) {
            _error(`Token Error: ${data.error}`);
            updateStatus(`❌ Error: ${data.error}`);
            return;
        }

        if (!data.token) {
            _error('No token received from server');
            updateStatus('❌ No token received');
            return;
        }

        _log('Setting up Twilio Device...');

        // Initialize Twilio Device
        Twilio.Device.setup(data.token, {
            logLevel: 1,
        });

        device = Twilio.Device;

        device.on('ready', function() {
            _log('Device is ready');
            updateStatus('✅ Ready to call - Click Call button');
            document.getElementById('call-btn').disabled = false;
        });

        device.on('error', function(error) {
            _error(`Device error: ${error.message}`);
            updateStatus(`❌ Device error: ${error.message}`);
            console.error('Device error:', error);
        });

        device.on('connect', function(connection) {
            _log('Call connected');
            activeConnection = connection;
            updateStatus('✅ Call connected');
            document.getElementById('call-btn').style.display = 'none';
            document.getElementById('end-btn').style.display = 'block';
            document.getElementById('mute-btn').style.display = 'block';
            document.getElementById('call-timer').style.display = 'block';
            document.getElementById('recording-status').style.display = 'block';

            startCallTimer();
            startRecording();
            updateCallStatus('answered');
        });

        device.on('disconnect', function(connection) {
            _log('Call disconnected');
            updateStatus('📞 Call disconnected');
            document.getElementById('call-btn').style.display = 'block';
            document.getElementById('end-btn').style.display = 'none';
            document.getElementById('mute-btn').style.display = 'none';
            document.getElementById('call-timer').style.display = 'none';
            document.getElementById('recording-status').style.display = 'none';

            clearInterval(timerInterval);
            stopRecording();
            updateCallStatus('completed');
        });

        device.on('incoming', function(connection) {
            _log('Incoming call');
            updateStatus('📲 Incoming call...');
            connection.accept();
        });

    } catch (error) {
        _error(`Initialization error: ${error.message}`);
        updateStatus(`❌ Init Error: ${error.message}`);
        console.error('Initialization error:', error);
    }
}

function makeCall() {
    _log('Making call to ' + customerNumber);

    if (!device) {
        _error('Device not initialized');
        updateStatus('❌ Device not ready');
        return;
    }

    if (!customerNumber) {
        _error('No customer phone number');
        updateStatus('❌ No phone number');
        return;
    }

    const params = { To: customerNumber };

    updateStatus('📞 Calling...');
    updateCallStatus('ringing');

    try {
        device.connect(params);
    } catch (err) {
        _error(`Call error: ${err.message}`);
        updateStatus(`❌ ${err.message}`);
    }
}

function endCall() {
    _log('Ending call');
    if (activeConnection) {
        activeConnection.disconnect();
        activeConnection = null;
    }
}

function toggleMute() {
    if (activeConnection) {
        isMuted = !isMuted;
        activeConnection.mute(isMuted);
        document.getElementById('mute-btn').classList.toggle('active', isMuted);
        _log('Mute: ' + (isMuted ? 'ON' : 'OFF'));
    }
}

function startCallTimer() {
    callStartTime = Date.now();
    timerInterval = setInterval(function() {
        const elapsed = Math.floor((Date.now() - callStartTime) / 1000);
        const hours = Math.floor(elapsed / 3600);
        const minutes = Math.floor((elapsed % 3600) / 60);
        const seconds = elapsed % 60;
        document.getElementById('timer').textContent =
            String(hours).padStart(2, '0') + ':' +
            String(minutes).padStart(2, '0') + ':' +
            String(seconds).padStart(2, '0');
    }, 1000);
}

function startRecording() {
    _log('Starting recording...');
    try {
        navigator.mediaDevices.getUserMedia({ audio: true })
            .then(stream => {
                mediaRecorder = new MediaRecorder(stream);
                audioChunks = [];

                mediaRecorder.ondataavailable = (event) => {
                    audioChunks.push(event.data);
                };

                mediaRecorder.onstop = () => {
                    const audioBlob = new Blob(audioChunks, { type: 'audio/wav' });
                    _log('Recording stopped, saving...');
                    saveRecording(audioBlob);
                    stream.getTracks().forEach(track => track.stop());
                };

                mediaRecorder.start();
                _log('Recording started');
                document.getElementById('recording-text').textContent = 'Recording in progress...';
            })
            .catch(error => {
                _error(`Microphone access denied: ${error.message}`);
                updateStatus('❌ Microphone access denied');
            });
    } catch (error) {
        _error(`Recording start error: ${error.message}`);
    }
}

function stopRecording() {
    if (mediaRecorder && mediaRecorder.state !== 'inactive') {
        _log('Stopping recorder...');
        mediaRecorder.stop();
    }
}

async function saveRecording(audioBlob) {
    try {
        _log('Converting recording to base64...');
        const reader = new FileReader();
        reader.onload = async function(e) {
            const recordingBlob = e.target.result;

            _log('Sending recording to server...');
            const response = await fetch(`/twilio/call/${callId}/save-recording`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    recordingBlob: recordingBlob,
                }),
            });

            const data = await response.json();

            if (data.success) {
                _log('Recording saved successfully');
                updateStatus('✅ Recording saved and being transcribed with Gemini AI...');
                document.getElementById('recording-text').textContent = 
                    'Processing recording...';
            } else {
                _error(`Save failed: ${data.error}`);
            }
        };
        reader.readAsDataURL(audioBlob);
    } catch (error) {
        _error(`Save recording error: ${error.message}`);
    }
}

function testAudio() {
    _log('Testing speaker...');
    // Play a test tone
    const audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);

    oscillator.frequency.value = 1000;
    gainNode.gain.setValueAtTime(0.1, audioContext.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 1);

    oscillator.start(audioContext.currentTime);
    oscillator.stop(audioContext.currentTime + 1);

    updateStatus('🔊 Speaker test - you should hear a tone');
}

async function testMicrophone() {
    _log('Testing microphone...');
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        stream.getTracks().forEach(track => track.stop());
        updateStatus('✅ Microphone working!');
        _log('Microphone test successful');
    } catch (error) {
        _error(`Microphone test failed: ${error.message}`);
        updateStatus(`❌ Microphone test failed: ${error.message}`);
    }
}

function updateStatus(message) {
    _log('Status: ' + message);
    document.getElementById('call-status').textContent = message;
}

async function updateCallStatus(status) {
    try {
        await fetch(`/twilio/call/${callId}/update-status`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({ status: status }),
        });
        _log('Call status updated to: ' + status);
    } catch (error) {
        console.error('Status update error:', error);
    }
}
